Cryptography is essential for securing data and communications.

## Symmetric Encryption
Same key for encryption and decryption.

```javascript
const crypto = require('crypto');

// AES-256-CBC
const algorithm = 'aes-256-cbc';
const key = crypto.randomBytes(32);
const iv = crypto.randomBytes(16);

function encrypt(text) {
    const cipher = crypto.createCipheriv(algorithm, key, iv);
    let encrypted = cipher.update(text, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    return { iv: iv.toString('hex'), encryptedData: encrypted };
}

function decrypt(encrypted) {
    const decipher = crypto.createDecipheriv(
        algorithm,
        key,
        Buffer.from(encrypted.iv, 'hex')
    );
    let decrypted = decipher.update(encrypted.encryptedData, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
}
```

## Asymmetric Encryption
Public/private key pair.

```javascript
const { generateKeyPairSync, publicEncrypt, privateDecrypt } = require('crypto');

const { publicKey, privateKey } = generateKeyPairSync('rsa', {
    modulusLength: 2048,
});

const encrypted = publicEncrypt(publicKey, Buffer.from('Secret data'));
const decrypted = privateDecrypt(privateKey, encrypted);
```

## Hashing
One-way functions for data integrity.

```javascript
const crypto = require('crypto');

// SHA-256
const hash = crypto.createHash('sha256').update('password123').digest('hex');

// bcrypt (for passwords)
const bcrypt = require('bcryptjs');
const salt = await bcrypt.genSalt(10);
const hash = await bcrypt.hash('password123', salt);
const match = await bcrypt.compare('password123', hash);
```

## Digital Signatures
```javascript
const { sign, verify } = require('crypto');

const signer = sign('sha256', Buffer.from('Message'), privateKey);
const signature = signer.toString('base64');

const verifier = verify('sha256', Buffer.from('Message'), publicKey, Buffer.from(signature, 'base64'));
```

## TLS/SSL

HTTPS ensures encrypted communication between client and server.
```bash
# Generate self-signed certificate
openssl req -x509 -nodes -days 365 -newkey rsa:2048 -keyout private.key -out certificate.crt
```

Understanding cryptography is fundamental to building secure applications.

